python3 -c "
import json, sys

with open('/workspace/notes.json') as f:
    notes = json.load(f)

errors = []

# Must be a list
if not isinstance(notes, list):
    errors.append('Root is not a JSON array')
    print(json.dumps(errors))
    sys.exit(1)

# Each element must have exactly 4 keys with correct types
required_keys = {'onset_sec', 'offset_sec', 'pitch_midi', 'velocity'}
for i, note in enumerate(notes):
    if set(note.keys()) != required_keys:
        errors.append(f'Note {i}: keys={set(note.keys())}, expected={required_keys}')
    if not isinstance(note['onset_sec'], (int, float)):
        errors.append(f'Note {i}: onset_sec type={type(note[\"onset_sec\"]).__name__}')
    if not isinstance(note['offset_sec'], (int, float)):
        errors.append(f'Note {i}: offset_sec type={type(note[\"offset_sec\"]).__name__}')
    if not isinstance(note['pitch_midi'], int):
        errors.append(f'Note {i}: pitch_midi type={type(note[\"pitch_midi\"]).__name__}')
    if not isinstance(note['velocity'], int):
        errors.append(f'Note {i}: velocity type={type(note[\"velocity\"]).__name__}')
    if note['offset_sec'] <= note['onset_sec']:
        errors.append(f'Note {i}: offset_sec ({note[\"offset_sec\"]}) <= onset_sec ({note[\"onset_sec\"]})')
    if not (0 <= note['pitch_midi'] <= 127):
        errors.append(f'Note {i}: pitch_midi={note[\"pitch_midi\"]} out of [0,127]')
    if not (1 <= note['velocity'] <= 127):
        errors.append(f'Note {i}: velocity={note[\"velocity\"]} out of [1,127]')

# Sorted by onset_sec
for i in range(len(notes) - 1):
    if notes[i]['onset_sec'] >= notes[i+1]['onset_sec']:
        errors.append(f'Not sorted: note {i} onset={notes[i][\"onset_sec\"]} >= note {i+1} onset={notes[i+1][\"onset_sec\"]}')

# offset_sec <= duration + tolerance
import soundfile as sf
info = sf.info('/workspace/input.wav')
duration = info.duration
for i, note in enumerate(notes):
    if note['offset_sec'] > duration + 0.1:
        errors.append(f'Note {i}: offset_sec={note[\"offset_sec\"]} > duration+tol={duration+0.1:.4f}')

if errors:
    print('FAILED:')
    for e in errors:
        print(f'  - {e}')
else:
    print(f'ALL CHECKS PASSED. {len(notes)} notes, duration={duration:.3f}s')
"
